// Parse and normalize lead data from different sources
const normalizedLeads = [];

for (const item of $input.all()) {
  const source = item.json.source || 'unknown';
  const rawData = item.json;

  let lead = {
    companyName: '',
    email: '',
    domain: '',
    industry: '',
    employees: null,
    revenue: null,
    source: source,
    rawData: rawData
  };

  // Parse based on source type
  if (source === 'directory' || rawData.type === 'directory') {
    lead.companyName = rawData.company || rawData.companyName || rawData.name || '';
    lead.email = rawData.email || rawData.contactEmail || '';
    lead.domain = rawData.website || rawData.domain || '';
    lead.industry = rawData.industry || rawData.sector || '';
    lead.employees = rawData.employees || rawData.employeeCount || null;
    lead.revenue = rawData.revenue || rawData.annualRevenue || null;
  } 
  else if (source === 'rss' || rawData.type === 'rss') {
    // Extract from RSS feed items
    lead.companyName = rawData.title || rawData.company || '';
    lead.email = rawData.email || '';
    lead.domain = rawData.link ? new URL(rawData.link).hostname : '';
    lead.industry = rawData.category || rawData.industry || '';
  }
  else if (source === 'social' || rawData.type === 'social') {
    lead.companyName = rawData.companyName || rawData.organization || rawData.name || '';
    lead.email = rawData.email || rawData.contactEmail || '';
    lead.domain = rawData.website || rawData.url || '';
    lead.industry = rawData.industry || '';
    lead.employees = rawData.employeeCount || rawData.size || null;
  }
  else if (source === 'jobboard' || rawData.type === 'jobboard') {
    lead.companyName = rawData.company || rawData.employer || '';
    lead.email = rawData.applicationEmail || rawData.email || '';
    lead.domain = rawData.companyWebsite || rawData.website || '';
    lead.industry = rawData.industry || rawData.sector || '';
  }
  else {
    // Generic fallback parsing
    lead.companyName = rawData.companyName || rawData.company || rawData.name || '';
    lead.email = rawData.email || rawData.contactEmail || '';
    lead.domain = rawData.domain || rawData.website || '';
    lead.industry = rawData.industry || '';
    lead.employees = rawData.employees || rawData.employeeCount || null;
    lead.revenue = rawData.revenue || null;
  }

  // Clean up domain (remove protocol, www, etc.)
  if (lead.domain) {
    lead.domain = lead.domain.replace(/^(https?:\/\/)?(www\.)?/, '').split('/')[0];
  }

  // Convert employee count to number if string
  if (typeof lead.employees === 'string') {
    lead.employees = parseInt(lead.employees.replace(/[^0-9]/g, '')) || null;
  }

  // Convert revenue to number if string
  if (typeof lead.revenue === 'string') {
    lead.revenue = parseFloat(lead.revenue.replace(/[^0-9.]/g, '')) || null;
  }

  normalizedLeads.push({ json: lead });
}

return normalizedLeads;
